<template>
  <div class="shellContainer" v-if="showModel === 'button'" >
    <el-button v-loading="isRunning" class="shellButton" round type="primary"
               @click="openDrawer">shell 输出
    </el-button>
  </div>

  <el-drawer v-model="state.showDrawer" direction="btt" :lock-scroll="false" v-if="showModel === 'button'"
             :before-close="drawerClose" :modal="true" :show-close="true" :append-to-body="false" modal-class="shellModalDrawer">
    <template #default>
      <el-scrollbar>
        <button style="top:0px;position: absolute;">fff</button>
          <div id="showShellResult" class="sticky-textarea" v-html="shellShowResult"></div>
      </el-scrollbar>
    </template>
  </el-drawer>

  <el-scrollbar v-if="showModel === 'div'">
    <div id="showShellResult" class="sticky-textarea-div" :style="{ height: divHeight + 'px' }" v-html="shellShowResult"></div>
  </el-scrollbar>
</template>

<style scoped>
.shellButton {

}

.sticky-textarea-div {
  background-color: rgb(84, 92, 100);
  overflow-y: scroll;
  color: #F8F8FF;
  line-height: 1.5;
  font-size: 12px;
  word-break: break-all;
  text-align: left;
  font-family: Consolas;
  padding:3px;
  margin-top:3px;
}

.sticky-textarea {
  height:250px;
  background-color: #042028;
  overflow-y: scroll;
  color: #cccccc;
  line-height: 1.5;
  font-size: 12px;
  word-break: break-all;
  text-align: left;
  font-family: Consolas;
  padding:3px;
}
</style>

<script>
import {defineExpose, defineComponent, inject, defineEmits, getCurrentInstance, reactive} from 'vue';

export default defineComponent({
  props: {
    shellShowResult: {
      type: String
    },
    showModel: {
      type: String
    },
    isRunning: {
      type: Boolean
    },
    divHeight : {
      type : Number,
    }
  },
  setup(props) {
    const proxy = getCurrentInstance().proxy
    const openDrawer = function (){
      if(state.showDrawer){
        return
      }
      state.showDrawer = !state.showDrawer
      setTimeout(function(){
        let obj = document.getElementById('showShellResult')
        if (obj) {
          obj.scrollTop = obj.scrollHeight + 200
        }
      } , 500)
    };
    const state = reactive({
      showDrawer: false,
    });
    const drawerClose = function (){
      state.showDrawer = false
      // proxy.$confirm('确定关闭吗', '提示', {
      //   confirmButtonText: '确定',
      //   cancelButtonText: '取消',
      //   type: 'warning',
      // })
      //     .then(() => {
      //       state.showDrawer = false
      //     })
      //     .catch(() => {
      //       return false
      //     })
    };

    return {
      state,
      drawerClose,
      openDrawer,
    }
  }
})
</script>